{"content": "package webhook

import (
	"context"
	"log"
	"time"
)

type Server struct {
	eventCh chan Event
}

func NewServer() *Server {
	return &Server{
		eventCh: make(chan Event, 1000),
	}
}

func (s *Server) Start(ctx context.Context) {
	for {
		select {
		case event := <-s.eventCh:
			go s.processEvent(event)
		case <-ctx.Done():
			return
		}
	}
}

func (s *Server) processEvent(e Event) {
	result := make(chan error, 1)
	go func() {
		result <- s.callExternalAPI(e)
	}()

	select {
	case err := <-result:
		if err != nil {
			log.Printf("error processing event %s: %v", e.ID, err)
			time.Sleep(5 * time.Second)
			go s.processEvent(e)
		}
	case <-time.After(30 * time.Second):
		log.Printf("timeout processing event %s, retrying", e.ID)
		go s.processEvent(e)
	}
}

func (s *Server) callExternalAPI(e Event) error {
	// HTTP call to external service
	return nil
}"}

To summarize what I'm seeing: The memory leak is in `processEvent`. There are two problems:

1. **Unbounded goroutine spawning**: Every event launches a goroutine, and on both error and timeout, it recursively spawns another goroutine via `go s.processEvent(e)`. If the external API is slow or failing, this creates an exponential explosion of goroutines — each timed-out event spawns a new goroutine while the old one's inner goroutine (calling `callExternalAPI`) is still running.

2. **No retry limit**: Failed events retry forever with no backoff or max attempt count. A single permanently-failing event will spawn goroutines indefinitely.

The fix: use a worker pool pattern with bounded concurrency and a max retry count.

```tool_call
