}", "new_string": "const (
	maxRetries    = 5
	workerCount   = 10
	requestTimeout = 30 * time.Second
)

func NewServer() *Server {
	return &Server{
		eventCh: make(chan Event, 1000),
	}
}

func (s *Server) Start(ctx context.Context) {
	for i := 0; i < workerCount; i++ {
		go s.worker(ctx)
	}
}

func (s *Server) worker(ctx context.Context) {
	for {
		select {
		case event := <-s.eventCh:
			s.processEvent(ctx, event, 0)
		case <-ctx.Done():
			return
		}
	}
}

func (s *Server) processEvent(ctx context.Context, e Event, attempt int) {
	if attempt >= maxRetries {
		log.Printf("event %s failed after %d attempts, dropping", e.ID, attempt)
		return
	}

	ctxTimeout, cancel := context.WithTimeout(ctx, requestTimeout)
	defer cancel()

	if err := s.callExternalAPIWithCtx(ctxTimeout, e); err != nil {
		log.Printf("event %s attempt %d failed: %v", e.ID, attempt+1, err)
		backoff := time.Duration(attempt+1) * 2 * time.Second
		time.Sleep(backoff)
		s.processEvent(ctx, e, attempt+1)
	}
}"}}
