So the situation is: The Go server uses `gorilla/mux` with no CORS handling at all — no middleware, no `Access-Control` headers anywhere in the codebase. The browser blocks cross-origin requests from `localhost:3000` to `localhost:8080` because the server never responds with CORS headers. I'll add CORS middleware directly since it's a small setup.

```tool_call
{"name": "edit_file", "arguments": {"path": "cmd/server/main.go", "old_string": "package main

import (
	"log"
	"net/http"

	"github.com/gorilla/mux"
	"myapp/internal/handlers"
)

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/api/items", handlers.GetItems).Methods("GET")
	r.HandleFunc("/api/items", handlers.CreateItem).Methods("POST")
	r.HandleFunc("/api/items/{id}", handlers.DeleteItem).Methods("DELETE")

	log.Println("Server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", r))
}", "new_string": "package main

import (
	"log"
	"net/http"

	"github.com/gorilla/mux"
	"myapp/internal/handlers"
)

func corsMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Access-Control-Allow-Origin", "http://localhost:3000")
		w.Header().Set("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS")
		w.Header().Set("Access-Control-Allow-Headers", "Content-Type, Authorization")

		if r.Method == "OPTIONS" {
			w.WriteHeader(http.StatusOK)
			return
		}

		next.ServeHTTP(w, r)
	})
}

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/api/items", handlers.GetItems).Methods("GET")
	r.HandleFunc("/api/items", handlers.CreateItem).Methods("POST")
	r.HandleFunc("/api/items/{id}", handlers.DeleteItem).Methods("DELETE")

	handler := corsMiddleware(r)

	log.Println("Server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", handler))
}"}}
