{"content": "import { useMemo } from 'react';

interface StatsData {
  revenue: number;
  orders: number;
  customers: number;
  topProducts: { name: string; sales: number }[];
}

interface Props {
  data: StatsData;
  onRefresh: () => void;
  filters: Record<string, string>;
}

export function DashboardStats({ data, onRefresh, filters }: Props) {
  const sortedProducts = data.topProducts
    .slice()
    .sort((a, b) => b.sales - a.sales)
    .slice(0, 5);

  const totalSales = data.topProducts.reduce((sum, p) => sum + p.sales, 0);

  return (
    <div className="stats-grid">
      <div className="stat-card">
        <h3>Revenue</h3>
        <p>${data.revenue.toLocaleString()}</p>
      </div>
      <div className="stat-card">
        <h3>Orders</h3>
        <p>{data.orders}</p>
      </div>
      <div className="stat-card">
        <h3>Customers</h3>
        <p>{data.customers}</p>
      </div>
      <div className="products-list">
        <h3>Top Products (Total: {totalSales})</h3>
        {sortedProducts.map(p => (
          <div key={p.name}>{p.name}: {p.sales}</div>
        ))}
      </div>
      <button onClick={onRefresh}>Refresh</button>
    </div>
  );
}"}

