redis.on('error', () => { redisHealthy = false; });
redis.on('connect', () => { redisHealthy = true; });

export async function cached<T>(
  key: string,
  ttl: number,
  fetcher: () => Promise<T>
): Promise<T> {
  // Skip cache entirely if Redis is down
  if (!redisHealthy) {
    return fetcher();
  }

  try {
    const hit = await redis.get(key);
    if (hit) {
      return JSON.parse(hit);
    }
  } catch {
    // Redis read failed — fall through to fetcher
    return fetcher();
  }

  const data = await fetcher();

  // Fire-and-forget write — don't slow down the response
  redis.set(key, JSON.stringify(data), 'EX', ttl).catch(() => {});

  return data;
}
