Based on what I've read: The `Item` model uses `cuid()` string IDs and has a `createdAt` field. The list endpoint returns all items with no limit. I'll implement cursor-based pagination using the `id` field as the cursor (Prisma has native support for this). Cursor pagination is better than offset pagination for large datasets because it doesn't slow down on later pages.

```tool_call
{"name": "edit_file", "arguments": {"path": "src/routes/items.ts", "old_string": "// List all items
router.get('/', async (req, res) => {
  const items = await prisma.item.findMany({ orderBy: { createdAt: 'desc' } });
  res.json({ items });
});", "new_string": "// List items with cursor-based pagination
router.get('/', async (req, res) => {
  const limit = Math.min(parseInt(req.query.limit as string) || 20, 100);
  const cursor = req.query.cursor as string | undefined;

  const items = await prisma.item.findMany({
    take: limit + 1,
    ...(cursor && {
      cursor: { id: cursor },
      skip: 1, // Skip the cursor item itself
    }),
    orderBy: { createdAt: 'desc' },
  });

  const hasMore = items.length > limit;
  const results = hasMore ? items.slice(0, limit) : items;
  const nextCursor = hasMore ? results[results.length - 1].id : null;

  res.json({
    items: results,
    pagination: {
      nextCursor,
      hasMore,
    },
  });
});"}}
