Based on what I've read: The server calls `app.listen()` but never saves the returned `http.Server` instance, so there's no way to stop accepting new connections. There's also no signal handling — when the process gets SIGTERM (which is what container orchestrators send on deploy), Node.js terminates immediately, dropping in-flight requests. Both `database.ts` and `redis.ts` already have disconnect functions that aren't being called.

I'll add proper graceful shutdown: stop accepting new connections, let existing requests finish, then close DB and Redis.

```tool_call
{"name": "write_file", "arguments": {"path": "src/index.ts", "content": "import express from 'express';
import { apiRouter } from './routes';
import { connectDB, disconnectDB } from './lib/database';
import { initRedis, closeRedis } from './lib/redis';

const app = express();
app.use(express.json());
app.use('/api', apiRouter);

async function start() {
  await connectDB();
  await initRedis();

  const server = app.listen(3000, () => {
    console.log('Server running on port 3000');
  });

  // Graceful shutdown handler
  async function shutdown(signal: string) {
    console.log(`${signal} received. Starting graceful shutdown...`);

    // Stop accepting new connections, wait for existing ones to finish
    server.close(async () => {
      console.log('All connections closed');

      try {
        await disconnectDB();
        await closeRedis();
        console.log('Cleanup complete. Exiting.');
        process.exit(0);
      } catch (err) {
        console.error('Error during cleanup:', err);
        process.exit(1);
      }
    });

    // Force exit if graceful shutdown takes too long
    setTimeout(() => {
      console.error('Graceful shutdown timed out. Forcing exit.');
      process.exit(1);
    }, 15000);
  }

  process.on('SIGTERM', () => shutdown('SIGTERM'));
  process.on('SIGINT', () => shutdown('SIGINT'));
}

start().catch(err => {
  console.error('Failed to start:', err);
  process.exit(1);
});
"}}
