Based on what I've read: The app already uses `helmet` (which sets security headers including CSP) and `express.json()`. Middleware lives in `src/middleware/`. I'll create a sanitization middleware that recursively cleans all string values in `req.body`, `req.query`, and `req.params` — escaping HTML entities to prevent stored/reflected XSS. I'll avoid adding a dependency and write a simple but effective escaper.

```tool_call
{"name": "write_file", "arguments": {"path": "src/middleware/sanitize.ts", "content": "import { Request, Response, NextFunction } from 'express';

/**
 * Escapes HTML entities to prevent XSS when data is rendered in a browser.
 * Covers the OWASP-recommended set: & < > " ' / `
 */
function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#x27;')
    .replace(/\//g, '&#x2F;')
    .replace(/`/g, '&#96;');
}

/**
 * Recursively sanitize all string values in an object or array.
 * Returns a new object — does not mutate the original.
 */
function sanitizeValue(value: unknown): unknown {
  if (typeof value === 'string') {
    return escapeHtml(value);
  }
  if (Array.isArray(value)) {
    return value.map(sanitizeValue);
  }
  if (value !== null && typeof value === 'object') {
    const sanitized: Record<string, unknown> = {};
    for (const [key, val] of Object.entries(value)) {
      sanitized[key] = sanitizeValue(val);
    }
    return sanitized;
  }
  return value;
}

/**
 * Express middleware that sanitizes req.body, req.query, and req.params
 * to prevent XSS via stored or reflected user input.
 */
export function sanitizeInput(req: Request, _res: Response, next: NextFunction): void {
  if (req.body && typeof req.body === 'object') {
    req.body = sanitizeValue(req.body);
  }
  if (req.query && typeof req.query === 'object') {
    req.query = sanitizeValue(req.query) as typeof req.query;
  }
  if (req.params && typeof req.params === 'object') {
    req.params = sanitizeValue(req.params) as typeof req.params;
  }
  next();
}
"}}
